export function script(input) {
  const defaultWords = ['www', 'api', 'app', 'dev', 'staging', 'test', 'admin', 'portal', 'cdn', 'beta'];
  const intensityLimits = { safe: 10, normal: 30, thorough: 75 };
  const requestedIntensity = String(input.scanIntensity || 'safe').trim().toLowerCase();
  const intensity = Object.prototype.hasOwnProperty.call(intensityLimits, requestedIntensity) ? requestedIntensity : 'safe';
  const wordLimit = intensityLimits[intensity];
  function normalizeDomain(value) {
    const raw = String(value || '').trim().toLowerCase();
    const stripped = raw.replace(/^https?:\/\//, '').replace(/\/.*$/, '').replace(/\.$/, '');
    return stripped.replace(/[^a-z0-9.-]/g, '');
  }
  const domain = normalizeDomain(input.domain);
  function asList(value) {
    if (Array.isArray(value)) return value;
    if (typeof value === 'string' && value.trim()) return value.split(/[\n,]+/);
    return [];
  }
  function cleanSubdomain(value) {
    const subdomain = normalizeDomain(value);
    if (!subdomain || !subdomain.endsWith(`.${domain}`)) return null;
    return subdomain;
  }
  function cleanWord(value) {
    const raw = String(value || '').trim().toLowerCase();
    if (!raw || raw.includes('..') || raw.includes('/') || /^https?:\/\//i.test(raw)) return '';
    return raw.replace(/^\.+/, '').replace(/\.+$/, '').replace(/[^a-z0-9-]/g, '');
  }
  const knownSubdomains = Array.from(new Set(asList(input.knownSubdomains).map(cleanSubdomain).filter(Boolean)));
  const requestedWords = asList(input.wordlist);
  const sourceWords = requestedWords.length > 0 ? requestedWords : defaultWords;
  const wordlist = [];
  const seenWords = new Set();
  for (const word of sourceWords) {
    const cleaned = cleanWord(word);
    if (!cleaned || seenWords.has(cleaned)) continue;
    seenWords.add(cleaned);
    wordlist.push(cleaned);
    if (wordlist.length >= wordLimit) break;
  }
  if (wordlist.length === 0) wordlist.push('www');
  return {
    domain,
    domains: domain ? [domain] : [],
    knownSubdomains,
    wordlist,
    scanProfile: {
      intensity,
      rootDomain: domain,
      knownSubdomains: knownSubdomains.length,
      requestedWordCount: requestedWords.length,
      wordCount: wordlist.length,
      wordLimit,
      truncatedByIntensity: Math.max(0, sourceWords.length - wordlist.length),
    },
  };
}

